div.script:
        // Fetch the raw text from 'file.txt' in the same directory
        fetch('file.txt')
          .then(response => {
            if (!response.ok) {
              throw new Error('Network response was not ok: ' + response.statusText);
            }
            return response.text();
          })
          .then(htmlContent => {
            // Use the srcdoc attribute to render the raw text as HTML inside the iframe
            document.getElementById('fullscreen-frame').srcdoc = htmlContent;
          })
          .catch(error => {
            console.error('Error fetching file:', error);
            document.getElementById('fullscreen-frame').srcdoc = 
              '
' +
              '
Error loading file.txt' +
              '
Check the console for more details. Note: Browsers may block local file fetching due to CORS policies if not run on a local server.' +
              '';
          });
